sql:
SELECT SUM(dp.volume) AS total_trading_volume
FROM daily_prices dp
WHERE dp.symbol = '0';

SELECT AVG(s.market_cap) AS average_market_cap
FROM stocks s
JOIN (
    SELECT DISTINCT symbol
    FROM dividends
) d ON s.symbol = d.symbol;

SELECT AVG(volume) AS average_volume, AVG(trading_hours) AS average_trading_hours
FROM daily_prices
WHERE symbol = '1';

SELECT close_price, high_price, low_price
FROM daily_prices
WHERE id = 1 AND symbol = '0' AND date = '2016-12-13';

SELECT symbol, company_name
FROM stocks
WHERE symbol = '1';

